1	import { LOGO_CURVE, lissajousPath } from "@repo/ui/lib/brand";
2	import { AbsoluteFill, continueRender, delayRender } from "@vendor/remotion";
3	import type React from "react";
4	import { useEffect, useMemo, useState } from "react";
5	import { ensureFontsLoaded } from "../landing-hero/shared/fonts";
6	
7	const CANVAS_W = 1200;
8	const CANVAS_H = 630;
9	const CX = CANVAS_W / 2;
10	const CY = CANVAS_H / 2;
11	
12	// 7 concentric rings: innermost is smallest, outermost is largest.
13	// Sizing: the outermost ring should nearly fill the shorter canvas dimension.
14	const RING_COUNT = 7;
15	const SIZE_MIN = 100;
16	const SIZE_MAX = 560;
17	
18	// Opacity: innermost ring is most opaque, outermost ring fades to ghost
19	const OPACITY_INNER = 0.82;
20	const OPACITY_OUTER = 0.08;
21	
22	// Padding fraction inside each ring's square canvas — tighter than default
23	const PADDING = 0.04;
24	
25	// Stroke weight scales slightly with ring size for visual coherence
26	const BASE_STROKE_W = 1.2;
27	
28	export const BlogFeaturedConcentric: React.FC = () => {
29	  const [handle] = useState(() => delayRender("Loading fonts"));
30	
31	  useEffect(() => {
32	    void ensureFontsLoaded()
33	      .then(() => continueRender(handle))
34	      .catch((err: unknown) => {
35	        console.error("Font loading failed:", err);
36	        continueRender(handle);
37	      });
38	  }, [handle]);
39	
40	  const rings = useMemo(() => {
41	    return Array.from({ length: RING_COUNT }, (_, i) => {
42	      // Linear interpolation from inner to outer
43	      const t = i / (RING_COUNT - 1);
44	      const size = SIZE_MIN + t * (SIZE_MAX - SIZE_MIN);
45	
46	      // Opacity decreases as rings grow outward
47	      const opacity = OPACITY_INNER + t * (OPACITY_OUTER - OPACITY_INNER);
48	
49	      // Stroke weight grows very slightly with size to preserve visual weight
50	      const strokeWidth = BASE_STROKE_W + t * 0.6;
51	
52	      // lissajousPath centers at (size/2, size/2) — translate to canvas center
53	      const tx = CX - size / 2;
54	      const ty = CY - size / 2;
55	
56	      const path = lissajousPath(
57	        size,
58	        PADDING,
59	        LOGO_CURVE.a,
60	        LOGO_CURVE.b,
61	        LOGO_CURVE.delta
62	      );
63	
64	      return { path, tx, ty, opacity, strokeWidth, size };
65	    });
66	  }, []);
67	
68	  return (
69	    <AbsoluteFill className="bg-background">
70	      <svg
71	        height={CANVAS_H}
72	        viewBox={`0 0 ${CANVAS_W} ${CANVAS_H}`}
73	        width={CANVAS_W}
74	      >
75	        {/* Render outer rings first so inner rings sit on top */}
76	        {[...rings].reverse().map((ring, idx) => (
77	          <g
78	            key={`ring-${RING_COUNT - 1 - idx}`}
79	            transform={`translate(${ring.tx.toFixed(2)}, ${ring.ty.toFixed(2)})`}
80	          >
81	            <path
82	              d={ring.path}
83	              fill="none"
84	              opacity={ring.opacity}
85	              stroke="var(--foreground)"
86	              strokeLinecap="round"
87	              strokeLinejoin="round"
88	              strokeWidth={ring.strokeWidth}
89	            />
90	          </g>
91	        ))}
92	
93	        {/* Subtle center registration mark — a pair of perpendicular hairlines */}
94	        <line
95	          opacity={0.12}
96	          stroke="var(--foreground)"
97	          strokeWidth={0.6}
98	          x1={CX - 12}
99	          x2={CX + 12}
100	          y1={CY}
101	          y2={CY}
102	        />
103	        <line
104	          opacity={0.12}
105	          stroke="var(--foreground)"
106	          strokeWidth={0.6}
107	          x1={CX}
108	          x2={CX}
109	          y1={CY - 12}
110	          y2={CY + 12}
111	        />
