  Vercel: "vercel",
  GitHub: "github",
  Sentry: "sentry",
  Linear: "linear",
};

const FEED_X = 512;
const FEED_Y = 0;
const FEED_WIDTH = 512;
const FEED_HEIGHT = 512;
const FEED_PADDING_X = 14;
const ROW_GAP = 8;

