  for (let offset = 0; offset < N && indices.length < MAX_VISIBLE; offset++) {
    const idx = (((newestEventIndex - offset) % N) + N) % N;
    const h = eventHeights[idx] ?? 0;

    // Check if this item fits (account for gap if not the first)
