    }
    renderItems.push({
      eventIndex: idx,
      event: FEED_EVENTS[idx]!,
      fromY: currAnchor + (currWindow.offsets[ci] ?? 0),
      toY: null,
      waveIndex: waveIdx++,
    });
  }

