import {
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "@vendor/remotion";
import type React from "react";
import { MOTION_DURATION, SPRING_CONFIGS } from "./timing";

interface IsometricCardProps {
  animate?: boolean;
  children: React.ReactNode;
  entranceFrame: number;
  height: number;
  /** Remove card background and border */
  transparent?: boolean;
  width: number;
  /** Absolute position within the isometric plane */
  x: number;
  y: number;
}

export const IsometricCard: React.FC<IsometricCardProps> = ({
  children,
  entranceFrame,
  animate = true,
  transparent = false,
  width,
  height,
  x,
  y,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const entrance = animate
    ? spring({
        frame: frame - entranceFrame,
        fps,
        config: SPRING_CONFIGS.SMOOTH,
        durationInFrames: MOTION_DURATION.CARD_ENTRANCE,
      })
    : 1;

  const translateY = interpolate(entrance, [0, 1], [40, 0]);
  const opacity = interpolate(entrance, [0, 1], [0, 1]);

  return (
    // Outer wrapper: positioning + 3D context
    <div
      className="absolute"
      style={{
        left: x,
        top: y,
        transform: `translateY(${translateY}px)`,
        opacity,
        width,
        height,
        transformStyle: "preserve-3d",
      }}
    >
      {/* Card background */}
      {!transparent && <div className="absolute inset-0 bg-card" />}
      {/* Children — clipped to card shape */}
      <div
        className="relative h-full w-full"
        style={{ transformStyle: "preserve-3d" }}
      >
        {children}
      </div>
      {/* Border overlay — always visible on top */}
      {!transparent && (
        <div className="pointer-events-none absolute inset-0 border border-border" />
      )}
    </div>
  );
};

import type { SpringConfig } from "@vendor/remotion";

export const SPRING_CONFIGS = {
  SMOOTH: { damping: 200 } satisfies Partial<SpringConfig>,
  GENTLE: { damping: 300 } satisfies Partial<SpringConfig>,
  SNAPPY: { damping: 20, stiffness: 200 } satisfies Partial<SpringConfig>,
} as const;

/** Shared animation durations (in frames) */
export const MOTION_DURATION = {
  GRID_DRAW: 44,
  GRID_OPACITY: 22,
  CARD_ENTRANCE: 36,
  ROW_ENTRANCE: 36,
  LOGO_MARK_ENTRANCE: 28,
  LOGO_ROTATION: 240,
} as const;

/** Frame offsets for each section's entrance */
export const SECTION_TIMING = {
  /** Grid lines draw in */
  GRID: { start: -MOTION_DURATION.GRID_DRAW },
  /** Section 1: Stream events card — cell (1,0) */
  STREAM_EVENTS: { start: 6, entrance: 6 },
  /** Section 2: Logo / engine — cell (1,1) */
  LOGO: { start: 48, entrance: 48 },
  /** Bottom row — cells (0,2), (1,2), (2,2) */
  BOTTOM_LEFT: { start: 78, entrance: 78 },
  BOTTOM_CENTER: { start: 88, entrance: 88 },
  BOTTOM_RIGHT: { start: 98, entrance: 98 },
} as const;

/** Beam animation — energy pulse traveling down grid columns to IngestedData */
export const BEAM_TIMING = {
  /** Frame when beams start traveling */
  START: 50,
  /** How many frames the beam takes to travel */
  TRAVEL_FRAMES: 50,
  /** Frame when beams arrive at IngestedData intersection (START + TRAVEL_FRAMES) */
  ARRIVAL: 100,
} as const;

/** Stagger delay between rows appearing inside cards */
export const ROW_STAGGER = {
  STREAM_EVENTS: 3,
  INGESTED_DATA: 24,
} as const;

