import { LOGO_CURVE, lissajousPoints } from "@repo/ui/lib/brand";
import { AbsoluteFill, continueRender, delayRender } from "@vendor/remotion";
import type React from "react";
import { useEffect, useMemo, useState } from "react";
import { ensureFontsLoaded } from "../landing-hero/shared/fonts";

const CANVAS_W = 1200;
const CANVAS_H = 630;
const CX = CANVAS_W / 2;
const CY = CANVAS_H / 2;

// Central Lissajous curve
const CURVE_SIZE = 280;

// Orbiting entity nodes
const NODE_COUNT = 12;
const ORBIT_RX = 420;
const ORBIT_RY = 220;
const NODE_RADIUS = 4;

// Connection lines from nodes to curve
const CONNECTION_OPACITY = 0.1;

// Labels
const VERSION_LABEL = "v0.1.0";

export const ChangelogV010Hero: React.FC = () => {
  const [handle] = useState(() => delayRender("Loading fonts"));

  useEffect(() => {
    void ensureFontsLoaded()
      .then(() => continueRender(handle))
      .catch((err: unknown) => {
        console.error("Font loading failed:", err);
        continueRender(handle);
      });
  }, [handle]);

  // Build Lissajous curve path centered on canvas
  const curvePath = useMemo(() => {
    const pts = lissajousPoints(
      LOGO_CURVE.a,
      LOGO_CURVE.b,
      LOGO_CURVE.delta,
      512
    );
    const halfSize = CURVE_SIZE / 2;
    const scaled = pts.map(
      ([x, y]) => [CX + x * halfSize, CY + y * halfSize] as const
    );
    const d = scaled
      .map(([x, y], i) => `${i === 0 ? "M" : "L"}${x.toFixed(2)},${y.toFixed(2)}`)
      .join(" ");
    return `${d} Z`;
  }, []);

  // Generate orbital node positions
  const nodes = useMemo(() => {
    return Array.from({ length: NODE_COUNT }, (_, i) => {
      const angle = (i / NODE_COUNT) * Math.PI * 2;
      const x = CX + Math.cos(angle) * ORBIT_RX;
      const y = CY + Math.sin(angle) * ORBIT_RY;
      const opacity = 0.3 + (Math.cos(angle * 2) + 1) * 0.35;
      return { x, y, opacity, angle };
    });
  }, []);

  // Nearest point on curve for each node (connection targets)
  const curveTargets = useMemo(() => {
    const pts = lissajousPoints(
      LOGO_CURVE.a,
      LOGO_CURVE.b,
      LOGO_CURVE.delta,
      512
    );
    const halfSize = CURVE_SIZE / 2;
    const scaled = pts.map(
      ([x, y]) => [CX + x * halfSize, CY + y * halfSize] as const
    );

    return nodes.map((node) => {
      let minDist = Number.POSITIVE_INFINITY;
      let closest = scaled[0];
      for (const pt of scaled) {
        const dx = pt[0] - node.x;
        const dy = pt[1] - node.y;
        const dist = dx * dx + dy * dy;
        if (dist < minDist) {
          minDist = dist;
          closest = pt;
        }
      }
      return closest;
    });
  }, [nodes]);

  return (
    <AbsoluteFill className="bg-background">
      <svg
        height={CANVAS_H}
        viewBox={`0 0 ${CANVAS_W} ${CANVAS_H}`}
        width={CANVAS_W}
      >
        {/* Connection lines from nodes to curve */}
        {nodes.map((node, i) => {
          const target = curveTargets[i];
          return (
            <line
              key={`conn-${i}`}
              opacity={CONNECTION_OPACITY}
              stroke="var(--foreground)"
              strokeDasharray="3 6"
              strokeWidth={0.8}
              x1={node.x.toFixed(2)}
              x2={target[0].toFixed(2)}
              y1={node.y.toFixed(2)}
              y2={target[1].toFixed(2)}
            />
          );
        })}

        {/* Orbital ellipse guide */}
        <ellipse
          cx={CX}
          cy={CY}
          fill="none"
          opacity={0.05}
          rx={ORBIT_RX}
          ry={ORBIT_RY}
          stroke="var(--foreground)"
          strokeWidth={0.6}
        />

        {/* Central Lissajous curve */}
        <path
          d={curvePath}
          fill="none"
          opacity={0.7}
          stroke="var(--foreground)"
          strokeLinecap="round"
          strokeLinejoin="round"
          strokeWidth={1.6}
        />

        {/* Entity nodes on the orbital ring */}
        {nodes.map((node, i) => (
          <g key={`node-${i}`}>
            {/* Glow halo */}
            <circle
              cx={node.x.toFixed(2)}
              cy={node.y.toFixed(2)}
              fill="var(--foreground)"
              opacity={node.opacity * 0.15}
              r={NODE_RADIUS * 2.5}
            />
            {/* Core dot */}
            <circle
              cx={node.x.toFixed(2)}
              cy={node.y.toFixed(2)}
              fill="var(--foreground)"
              opacity={node.opacity}
              r={NODE_RADIUS}
            />
          </g>
        ))}

        {/* Version label — bottom right */}
        <text
          dominantBaseline="auto"
          fill="var(--muted-foreground)"
          fontFamily="var(--font-sans)"
          fontSize={14}
          opacity={0.5}
          textAnchor="end"
          x={CANVAS_W - 40}
          y={CANVAS_H - 32}
        >
          {VERSION_LABEL}
        </text>
      </svg>
    </AbsoluteFill>
  );
};

