import { MANIFEST } from "./manifest";

// Component registry — maps manifest component names to actual React components
const COMPONENTS: Record<string, React.FC<Record<string, unknown>>> = {
  BlogFeaturedBase,
  BlogFeaturedConcentric,
  BlogFeaturedCross,
  BlogFeaturedDuo,
  BlogFeaturedGhost,
  BlogFeaturedLissajous,
  BlogFeaturedRule,
  BlogFeaturedTrail,
  ChangelogV010Events,
  ChangelogV010Hero,
  LandingHero,
  Logo,
  TwitterBanner,
  GitHubBanner,
};

export const RemotionRoot = () => {
  return (
    <>
      {Object.entries(MANIFEST.compositions).map(([id, entry]) => {
        const Component = COMPONENTS[entry.component];
        if (!Component) {
          throw new Error(`No component registered for composition "${id}"`);
        }

        if (entry.type === "video") {
          return (
            <Composition
              component={Component}
              durationInFrames={entry.durationInFrames}
              fps={entry.fps}
              height={entry.height}
              id={id}
              key={id}
              width={entry.width}
            />
          );
        }

        return (
          <Still
            component={Component}
            defaultProps={entry.props}
            height={entry.height}
            id={id}
            key={id}
            width={entry.width}
          />
        );
      })}
    </>
  );
};

